    'confidential-compute-action-gate':{label:'Confidential Compute Action Gate',eyebrow:'Architecture Fit',question:'How should confidential-compute posture become action-bound evidence without becoming reusable authorization?',purpose:'Route security and platform reviewers to the gate boundary between attested runtime posture and one proposed external effect.',inspect:['Action Acceptance','Local verification','Trust anchors','Security Review Kit','Evidence requirements'],groups:['actionacceptance','verify','trust','proof','resources'],contact:'confidential-compute-action-gate'},
